class ContractError(RuntimeError):
    pass


def run_git(args: list[str]) -> str:
    completed = subprocess.run(
        ["git", *args],
        cwd=str(REPO_ROOT),
        check=True,
        capture_output=True,
        text=True,
    )
    return completed.stdout.strip()


def sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest().upper()


def sha256_file(path: Path) -> str:
    return sha256_bytes(path.read_bytes())


def rel(path: Path) -> str:
    return path.relative_to(REPO_ROOT).as_posix()


def write_text(path: Path, text: str) -> None:
    with path.open("w", encoding="utf-8", newline="\n") as handle:
        handle.write(text)


def write_csv(path: Path, fieldnames: list[str], rows: list[dict[str, Any]]) -> None:
    with path.open("w", encoding="utf-8", newline="") as handle:
        writer = csv.DictWriter(handle, fieldnames=fieldnames, lineterminator="\n")
        writer.writeheader()
        for row in rows:
            writer.writerow({key: row.get(key, "") for key in fieldnames})


def read_csv(path: Path) -> list[dict[str, str]]:
    with path.open("r", encoding="utf-8-sig", newline="") as handle:
        return [dict(row) for row in csv.DictReader(handle)]


def count_words(text: str) -> int:
    return len(re.findall(r"\b[\w]+(?:[-'][\w]+)*\b", text, flags=re.UNICODE))


def verify_starting_state() -> None:
    if run_git(["branch", "--show-current"]) != EXPECTED_BRANCH:
        raise ContractError("Expected branch main.")
    if run_git(["rev-parse", "HEAD"]) != EXPECTED_HEAD:
        raise ContractError("Unexpected HEAD before 05BF.")
    if run_git(["log", "-1", "--format=%s"]) != EXPECTED_HEAD_MESSAGE:
        raise ContractError("Unexpected HEAD message before 05BF.")
    if run_git(["diff", "--name-only"]):
        raise ContractError("Tracked modifications are not allowed before 05BF.")
    if run_git(["diff", "--cached", "--name-only"]):
        raise ContractError("Staged files are not allowed before 05BF.")

    untracked = sorted(
        line.replace("\\", "/")
        for line in run_git(["ls-files", "--others", "--exclude-standard"]).splitlines()
        if line.strip()
    )
    if untracked != [SCRIPT_REL]:
        raise ContractError(
            f"Expected only the untracked 05BF generator, got: {untracked}"
        )

    if OUTPUT_DIR.exists():
        raise ContractError("05BF output directory already exists.")

    local_origin = run_git(["rev-parse", "refs/remotes/origin/main"])
    remote_rows = run_git(
        ["ls-remote", "--heads", "origin", "refs/heads/main"]
    ).splitlines()
    if len(remote_rows) != 1:
        raise ContractError("Expected exactly one remote origin/main row.")
    remote_head = remote_rows[0].split()[0]
    if local_origin != EXPECTED_HEAD or remote_head != EXPECTED_HEAD:
        raise ContractError("Local or remote origin/main is not at the secured 05BE checkpoint.")


def verify_sources() -> tuple[list[dict[str, str]], list[dict[str, str]], dict[str, Any]]:
    for relative_path, expected_hash in SOURCE_SHA256.items():
        path = REPO_ROOT / relative_path
        if not path.is_file():
            raise ContractError(f"Required source is missing: {relative_path}")
        actual_hash = sha256_file(path)
        if actual_hash != expected_hash:
            raise ContractError(
                f"SHA-256 mismatch for {relative_path}: {actual_hash}"
            )

    for relative_path, expected_blob in SOURCE_BLOBS.items():
        actual_blob = run_git(["rev-parse", f"{EXPECTED_HEAD}:{relative_path}"])
        if actual_blob != expected_blob:
            raise ContractError(
                f"Blob mismatch for {relative_path}: {actual_blob}"
            )

    manuscript_manifest = json.loads(SOURCE_PATHS["manuscript_manifest"].read_text(encoding="utf-8"))
    review_manifest = json.loads(SOURCE_PATHS["review_manifest"].read_text(encoding="utf-8"))

    if manuscript_manifest["status"] != "PASS":
        raise ContractError("05BD manifest status is not PASS.")
    if manuscript_manifest["counts"]["body_words"] != 7268:
        raise ContractError("05BD body-word contract is not 7,268.")
    if manuscript_manifest["counts"]["reference_entries"] != 22:
        raise ContractError("05BD reference count is not 22.")
    if manuscript_manifest["counts"]["tables"] != 4 or manuscript_manifest["counts"]["figures"] != 4:
        raise ContractError("05BD table or figure count mismatch.")

    if review_manifest["status"] != "PASS":
        raise ContractError("05BE audit execution did not pass.")
    expected_review_verdict = {
        "figure_integrity": "FAIL",
        "reviewer_readiness": "FAIL",
        "required_next_gate": "FIGURE_REPAIR_AND_INDEPENDENT_REVALIDATION_REQUIRED",
    }
    for key, expected in expected_review_verdict.items():
        if review_manifest["verdict"].get(key) != expected:
            raise ContractError(f"05BE verdict mismatch for {key}.")

    finding_ids = {row["finding_id"] for row in review_manifest["findings"]}
    if finding_ids != {"FIG-B01", "FIG-M01"}:
        raise ContractError("05BE figure finding set mismatch.")

    bootstrap_rows = read_csv(SOURCE_PATHS["bootstrap"])
    if len(bootstrap_rows) != 27:
        raise ContractError("Expected 27 bootstrap rows.")

    selected = [
        row for row in bootstrap_rows
        if row["metric"] in METRICS
    ]
    keys = {
        (row["metric"], row["degraded_condition"], row["stage"])
        for row in selected
    }
    expected_keys = {
        (metric, condition, stage)
        for metric in METRICS
        for condition in CONDITIONS
        for stage in STAGES
    }
    if len(selected) != 18 or keys != expected_keys:
        raise ContractError("Figure 1 source must contain the exact 18 metric-condition-stage rows.")

    parser_rows = [row for row in selected if row["metric"] == "parser_valid"]
    success_rows = [row for row in selected if row["metric"] == "stage_success"]
    if not all(float(row["mean_paired_delta_degraded_minus_clean"]) > 0 for row in parser_rows):
        raise ContractError("All nine parser-validity means must be positive.")
    parser_crossing = [
        row for row in parser_rows
        if float(row["ci_95_low"]) <= 0 <= float(row["ci_95_high"])
    ]
    if len(parser_crossing) != 3 or {
        row["degraded_condition"] for row in parser_crossing
    } != {"partial_dropout"}:
        raise ContractError("Expected three partial-dropout parser intervals crossing zero.")
    if not all(
        float(row["mean_paired_delta_degraded_minus_clean"]) < 0
        and float(row["ci_95_high"]) < 0
        for row in success_rows
    ):
        raise ContractError("All nine stage-success intervals must remain below zero.")

    cascade_rows = read_csv(SOURCE_PATHS["cascade"])
    all_rows = [row for row in cascade_rows if row["evidence_condition"] == "ALL"]
    if len(all_rows) != 1:
        raise ContractError("Expected one ALL cascade row.")
    all_row = all_rows[0]
    counts = json.loads(all_row["cascade_sequence_type_counts"])
    expected_counts = {
        "parser_failure_cascade": 143,
        "detected_not_recovered": 71,
        "audit_false_assurance": 3,
        "incomplete_persisted_sequence": 6,
        "preserved_or_clean_success": 17,
    }
    if counts != expected_counts:
        raise ContractError(f"Cascade family counts mismatch: {counts}")
    if sum(counts.values()) != 240:
        raise ContractError("Cascade family counts must sum to 240.")
    if int(all_row["cascade_failure_count"]) != 223:
        raise ContractError("Cascade failure count must be 223.")
    if float(all_row["cascade_failure_rate"]) != 0.929167:
        raise ContractError("Cascade failure rate must be 0.929167.")

    return selected, cascade_rows, {
        "manuscript_manifest": manuscript_manifest,
        "review_manifest": review_manifest,
        "cascade_counts": counts,
    }


def build_figure_01_rows(selected: list[dict[str, str]]) -> list[dict[str, Any]]:
    by_key = {
        (row["metric"], row["degraded_condition"], row["stage"]): row
        for row in selected
    }
    rows: list[dict[str, Any]] = []
    display_order = 0
    for condition in CONDITIONS:
        for stage in STAGES:
            for metric in METRICS:
                display_order += 1
                source = by_key[(metric, condition, stage)]
                rows.append({
                    "display_order": display_order,
                    "evidence_condition": condition,
                    "stage": stage,
                    "metric": metric,
                    "paired_cases": int(source["paired_cases"]),
                    "mean_delta_degraded_minus_clean": f'{float(source["mean_paired_delta_degraded_minus_clean"]):.6f}',
                    "ci_95_low": f'{float(source["ci_95_low"]):.6f}',
                    "ci_95_high": f'{float(source["ci_95_high"]):.6f}',
                    "bootstrap_n": int(source["bootstrap_n"]),
                    "random_seed": int(source["random_seed"]),
                    "authoritative_source": rel(SOURCE_PATHS["bootstrap"]),
                })
    return rows


def build_figure_04_rows(counts: dict[str, int]) -> list[dict[str, Any]]:
    order = [
        ("parser_failure_cascade", "Parser-failure cascade"),
        ("detected_not_recovered", "Detected but not recovered"),
        ("audit_false_assurance", "Audit false assurance"),
        ("incomplete_persisted_sequence", "Incomplete sequence"),
        ("preserved_or_clean_success", "Preserved success"),
    ]
    rows: list[dict[str, Any]] = []
    for index, (key, label) in enumerate(order, start=1):
        count = counts[key]
        rows.append({
            "display_order": index,
            "failure_family_key": key,
            "failure_family_label": label,
            "count": count,
            "total_sequence_groups": 240,
            "proportion": f"{count / 240:.6f}",
            "authoritative_source": rel(SOURCE_PATHS["cascade"]),
        })
    return rows


def build_repaired_manuscript(source: str) -> str:
    replacements = [
        (OLD_FIGURE_01_PATH, NEW_FIGURE_01_PATH),
        (OLD_FIGURE_01_CAPTION, NEW_FIGURE_01_CAPTION),
        (OLD_FIGURE_04_PATH, NEW_FIGURE_04_PATH),
        (OLD_FIGURE_04_CAPTION, NEW_FIGURE_04_CAPTION),
    ]

    repaired = source
    for old, new in replacements:
        if repaired.count(old) != 1:
            raise ContractError(
                f"Expected exactly one occurrence before replacement: {old[:80]}"
            )
        repaired = repaired.replace(old, new, 1)

    restored = repaired
    for old, new in reversed(replacements):
        if restored.count(new) != 1:
            raise ContractError(
                f"Expected exactly one repaired occurrence: {new[:80]}"
            )
        restored = restored.replace(new, old, 1)

    if restored != source:
        raise ContractError("Repaired manuscript is not reversible to byte-identical 05BD text.")

    source_body = source.split("## References", 1)[0]
    repaired_body = repaired.split("## References", 1)[0]
    if count_words(source_body) != count_words(repaired_body):
        raise ContractError(
            "Caption-only repair unexpectedly changed the body word count."
        )
    if source.count("\n- ") != repaired.count("\n- "):
        raise ContractError("Reference-entry structure changed unexpectedly.")

    expected_paths = [
        NEW_FIGURE_01_PATH,
        "../pilot_05_cfpb_glm52_paper_figures_tables/pilot_05AS_figure_02_audit_escalation_interpretation.png",
        "../pilot_05_cfpb_glm52_paper_figures_tables/pilot_05AS_figure_03_cascade_failure_rate.png",
        NEW_FIGURE_04_PATH,
    ]
    actual_paths = [
        match.group(1)
        for match in re.finditer(r"!\[[^\]]*\]\(([^)]+)\)", repaired)
    ]
    if actual_paths != expected_paths:
        raise ContractError(
            f"Repaired manuscript figure path/order mismatch: {actual_paths}"
        )

    return repaired


def build_traceability(
    figure_01_rows: list[dict[str, Any]],
    figure_04_rows: list[dict[str, Any]],
    repaired: str,
) -> str:
    parser_crossing = sum(
        1 for row in figure_01_rows
        if row["metric"] == "parser_valid"
        and float(row["ci_95_low"]) <= 0 <= float(row["ci_95_high"])
    )
    success_below = sum(
        1 for row in figure_01_rows
        if row["metric"] == "stage_success"
        and float(row["ci_95_high"]) < 0
    )
    return f"""# Task 05BF Figure Repair Traceability

## Purpose

This derivative package repairs only the two visual-evidence contracts rejected by the committed independent 05BE audit. It does not alter the committed 05AS assets or the committed 05BD manuscript.

## Figure 1 repair

- 05BE finding closed candidate: `FIG-B01`
- Authoritative source: `{rel(SOURCE_PATHS["bootstrap"])}`
- Source rows used: {len(figure_01_rows)}
- Parser-validity rows: 9
- Stage-success rows: 9
- Parser-validity point estimates above zero: 9/9
- Parser-validity intervals crossing zero: {parser_crossing}/9, all `partial_dropout`
- Stage-success intervals below zero: {success_below}/9
- Bootstrap contract: 2,000 resamples; seed 5205
- Corrected data: `{rel(OUTPUT_PATHS["figure_01_data"])}`
- Corrected asset: `{rel(OUTPUT_PATHS["figure_01_png"])}`
- PNG SHA-256: `{sha256_bytes(FIGURE_01_BYTES)}`

The corrected asset is a paired forest plot. Each evidence-condition and stage row contains one parser-validity estimate and one stage-success estimate with its 95% bootstrap interval and a zero reference line.

## Figure 4 repair

- 05BE finding closed candidate: `FIG-M01`
- Authoritative source: `{rel(SOURCE_PATHS["cascade"])}`
- Corrected data rows: {len(figure_04_rows)}
- Counts: parser failure 143; detected but not recovered 71; audit false assurance 3; incomplete sequence 6; preserved success 17
- Count sum: {sum(int(row["count"]) for row in figure_04_rows)}/240
- Corrected data: `{rel(OUTPUT_PATHS["figure_04_data"])}`
- Corrected asset: `{rel(OUTPUT_PATHS["figure_04_png"])}`
- PNG SHA-256: `{sha256_bytes(FIGURE_04_BYTES)}`

The corrected asset reports the authoritative sequence-family counts rather than row-presence fallback values.

## Manuscript rebinding

The repaired derivative manuscript is `{rel(OUTPUT_PATHS["manuscript"])}`. It differs from committed 05BD only through:

1. the Figure 1 asset path;
2. the Figure 1 caption;
3. the Figure 4 asset path;
4. the Figure 4 caption.

Undoing those four replacements restores the committed 05BD manuscript byte for byte. Figures 2 and 3, all four tables, all 22 references, numerical prose, uncertainty statements, conclusions, and limitations remain unchanged.

## Scope

This package creates no empirical evidence, model output, literature claim, or journal-readiness verdict. It prepares a traceable candidate for independent 05BG revalidation.
"""


