def build_validation_report(
    figure_01_rows: list[dict[str, Any]],
    figure_04_rows: list[dict[str, Any]],
    repaired: str,
) -> str:
    source = SOURCE_PATHS["manuscript"].read_text(encoding="utf-8")
    source_body = source.split("## References", 1)[0]
