def verify_final_state() -> None:
    if run_git(["rev-parse", "HEAD"]) != EXPECTED_HEAD:
        raise ContractError("HEAD changed during 05BF.")
    if run_git(["diff", "--name-only"]):
        raise ContractError("Tracked files changed during 05BF.")
    if run_git(["diff", "--cached", "--name-only"]):
        raise ContractError("Files were staged during 05BF.")
    untracked = sorted(
        line.replace("\\", "/")
        for line in run_git(["ls-files", "--others", "--exclude-standard"]).splitlines()
        if line.strip()
    )
    if untracked != EXPECTED_UNTRACKED:
        raise ContractError(
            f"Expected exactly ten 05BF untracked files, got: {untracked}"
        )


